import { useState, useEffect } from "react";
import API from "../services/api";
import { supabase } from "../services/supabaseClient";

export default function Upload({ user, setUser }) {
  const [file, setFile] = useState(null);
  const [text, setText] = useState("");
  const [summary, setSummary] = useState("");
  const [showSummary, setShowSummary] = useState(false);
  const [loading, setLoading] = useState(false);

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [asking, setAsking] = useState(false);

  const [docId, setDocId] = useState(null);
  const [userId, setUserId] = useState(null);

  const [papers, setPapers] = useState([]);
  const [loadingRec, setLoadingRec] = useState(false);

  // 💡 IDEAS STATE
  const [ideas, setIdeas] = useState([]);
  const [keywords, setKeywords] = useState([]);
  const [domain, setDomain] = useState("");
  const [subdomain, setSubdomain] = useState(""); // 🔥 FIXED

  // 🔥 AUTO TRIGGER
  const [autoRunIdeas, setAutoRunIdeas] = useState(false);

  // 🔐 Auth Header
  const getAuthHeader = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session ? { Authorization: `Bearer ${session.access_token}` } : {};
  };

  // 📄 Upload
  const handleUpload = async () => {
    if (!file) return alert("Select a file");

    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const formData = new FormData();
      formData.append("file", file);

      const res = await API.post("/upload", formData, {
        headers: {
          ...authHeader,
          "Content-Type": "multipart/form-data"
        }
      });

      setText(res.data.preview);
      setDocId(res.data.doc_id);
      setUserId(res.data.user_id);

      // reset states
      setAnswer("");
      setQuestion("");
      setSummary("");
      setShowSummary(false);
      setPapers([]);
      setIdeas([]);
      setKeywords([]);
      setDomain("");
      setSubdomain(""); // 🔥 reset

    } catch (err) {
      console.error(err);
      alert("Upload failed ❌");
    } finally {
      setLoading(false);
    }
  };

  // 💬 Q&A
  const askQuestion = async () => {
    if (!question || !docId) return alert("Upload + enter question");

    try {
      setAsking(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/ask", {
        question,
        doc_id: docId,
        user_id: userId
      }, { headers: authHeader });

      setAnswer(res.data.answer);

    } catch (err) {
      console.error(err);
    } finally {
      setAsking(false);
    }
  };

  // 🧠 Summary
  const handleGenerateSummary = async () => {
    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/summarize", { text }, { headers: authHeader });

      setSummary(res.data.summary);
      setShowSummary(true);

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // 🔍 Recommendations
  const handleRecommend = async () => {
    try {
      setLoadingRec(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/recommend", {
        query: text
      }, { headers: authHeader });

      setPapers(res.data.recommendations || []);

    } catch (err) {
      console.error(err);
    } finally {
      setLoadingRec(false);
    }
  };

  // 💡 IDEAS
  const handleIdeas = async () => {
    try {
      const authHeader = await getAuthHeader();

      const res = await API.post("/ideas", { text }, { headers: authHeader });

      setIdeas(res.data.ideas);
      setKeywords(res.data.keywords);
      setDomain(res.data.domain);
      setSubdomain(res.data.subdomain || ""); // 🔥 SAFE FIX

    } catch (err) {
      console.error(err);
      alert("Failed to generate ideas ❌");
    }
  };

  // 🔥 CHECK LOCALSTORAGE TRIGGER
  useEffect(() => {
    if (localStorage.getItem("runIdeas") === "true") {
      setAutoRunIdeas(true);
      localStorage.removeItem("runIdeas");
    }
  }, []);

  // 🔥 AUTO RUN AFTER UPLOAD
  useEffect(() => {
    if (autoRunIdeas && text) {
      handleIdeas();
      setAutoRunIdeas(false);
    }
  }, [autoRunIdeas, text]);

  return (
    <div id="upload-section" className="space-y-8">

      {/* Upload */}
      <div className="bg-white p-8 rounded-2xl shadow">
        <h2 className="text-xl font-bold mb-4">📄 Upload Research Paper</h2>

        <div className="flex gap-4">
          <input
            type="file"
            accept=".pdf"
            onChange={(e) => setFile(e.target.files[0])}
          />

          <button onClick={handleUpload} className="btn">
            {loading ? "Processing..." : "Upload"}
          </button>
        </div>
      </div>

      {/* Preview */}
      {text && (
        <div className="bg-gray-50 p-4 rounded">
          <h3 className="font-bold">Preview</h3>
          <p>{text.slice(0, 500)}...</p>
        </div>
      )}

      {/* Actions */}
      {text && (
        <div className="flex gap-4 flex-wrap">
          <button onClick={handleGenerateSummary} className="btn">🧠 Summary</button>
          <button onClick={handleRecommend} className="btn">🔍 Recommend</button>
          <button onClick={handleIdeas} className="btn">💡 Ideas</button>
        </div>
      )}

      {/* Summary */}
      {showSummary && (
        <div className="bg-blue-50 p-4 rounded">
          <h3 className="font-bold">Summary</h3>
          <p>{summary}</p>
        </div>
      )}

      {/* Q&A */}
      {text && (
        <div>
          <h3 className="font-bold">💬 Ask</h3>

          <input
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
            className="border p-2 w-full"
            placeholder="Ask question..."
          />

          <button onClick={askQuestion} className="btn mt-2">
            {asking ? "Thinking..." : "Ask"}
          </button>

          {answer && <p className="mt-3">{answer}</p>}
        </div>
      )}

      {/* Recommendations */}
      {papers.length > 0 && (
        <div>
          <h3 className="font-bold">📚 Related Papers</h3>
          {papers.map((p, i) => (
            <div key={i}>{p}</div>
          ))}
        </div>
      )}

      {/* 🔥 Domain + Keywords (UPDATED UI) */}
      {domain && (
        <div className="mt-6 bg-gradient-to-r from-indigo-50 to-blue-50 p-5 rounded-xl border border-indigo-100 shadow-sm">

          <h3 className="text-lg font-semibold text-indigo-700 mb-1">
            🧠 Domain: {domain}
          </h3>

          {subdomain && (
            <p className="text-sm text-gray-600 mb-3">
              Subdomain: {subdomain}
            </p>
          )}

          <div className="flex gap-2 flex-wrap">
            {keywords.map((k, i) => (
              <span
                key={i}
                className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-xs font-medium"
              >
                {k}
              </span>
            ))}
          </div>

        </div>
      )}

      {/* Ideas */}
      {ideas.length > 0 && (
        <div className="grid md:grid-cols-2 gap-4">

          {ideas.map((idea, i) => (
            <div key={i} className="bg-white p-4 rounded shadow border">

              <h3 className="font-bold">{idea.title}</h3>

              <p className="text-sm">{idea.description}</p>

              <p className="text-xs mt-2">💡 {idea.use_case}</p>

              <ul className="text-xs mt-2 list-disc ml-4">
                {idea.reasons?.map((r, idx) => (
                  <li key={idx}>{r}</li>
                ))}
              </ul>

              <div className="flex justify-between text-xs mt-2">
                <span>{idea.category}</span>
                <span>Score: {idea.score}</span>
              </div>

            </div>
          ))}

        </div>
      )}

    </div>
  );
}
